/**
 * Look up a YouTube URL for an exercise name from Jeff Nichols' channel.
 * Tries exact match first, then partial word match (60% threshold).
 * Returns null if no match — caller should fall back to YouTube search.
 */
export function findExerciseVideo(exerciseName: string): string | null {
  const query = exerciseName
    .toLowerCase()
    .replace(/^ex_/, "")
    .replace(/_/g, " ")
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  // 1. Exact match
  if (JEFF_NICHOLS_VIDEOS[query]) return JEFF_NICHOLS_VIDEOS[query];

  // 2. Query is a substring of a video title
  for (const [title, url] of Object.entries(JEFF_NICHOLS_VIDEOS)) {
    if (title.includes(query)) return url;
  }

  // 3. Partial word match — all significant query words appear in title
  const queryWords = query.split(" ").filter((w) => w.length > 2);
  if (queryWords.length === 0) return null;

  let bestMatch: string | null = null;
  let bestScore = 0;

  for (const [title, url] of Object.entries(JEFF_NICHOLS_VIDEOS)) {
    const matchCount = queryWords.filter((w) => title.includes(w)).length;
    const score = matchCount / queryWords.length;
    if (score > bestScore && score >= 0.6) {
      bestScore = score;
      bestMatch = url;
    }
  }

  return bestMatch;
}
